#include <bits/stdc++.h>
using namespace std;;

int n, m, d[800005], a[200005];

void push_up(int x)
{
    d[x] = max(d[x * 2], d[x * 2 + 1]);
}

void build(int x, int l, int r)
{
    if(l == r)
    {
        d[x] = a[l];
        return;
    }
    int mid = l + r >> 1;
    build(x * 2, l, mid), build(x * 2 + 1, mid + 1, r);
    push_up(x);
}

void update(int x, int l, int r, int a, int v)
{
    if(l == r)
    {
        d[x] = max(d[x], v);
        return;
    }
    int mid = l + r >> 1;
    if(a <= mid)
        update(x * 2, l, mid, a, v);
    else
        update(x * 2 + 1, mid + 1, r, a, v);
    push_up(x);
}

int query(int x, int l, int r, int a, int b)
{
    if(l >= a && r <= b) return d[x];
    int mid = l + r >> 1;
    if(b <= mid) 
        return query(x * 2, l, mid, a, b);
    if(a > mid)
        return query(x * 2 + 1, mid + 1, r, a, b);
    else
        return max(query(x * 2, l, mid, a, b), query(x * 2 + 1, mid + 1, r, a, b));
}

int main()
{
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    build(1, 1, n);
    for(int i = 1; i <= m; i++)
    {
        char op;int a, b;
        cin >> op >> a >> b;
        if(op == 'Q') cout << query(1, 1, n, a, b) << endl;
        else update(1, 1, n, a, b);
    }
}
